import React from 'react'; // Necessário para usar JSX

export const legalContent = {
  // --- SEÇÃO DA POLÍTICA DE PRIVACIDADE ---
  privacyPolicy: {
    title: "Política de Privacidade",
    lastUpdated: "Última atualização: 3 de Outubro de 2025",
    sections: [
      {
        title: "1. Introdução",
        content: (
          <p>
            A privacidade dos nossos visitantes e clientes é de extrema importância para a <strong>Cortex Studio</strong>. Esta política descreve os tipos de informações pessoais que coletamos, como elas são usadas e protegidas, e os seus direitos em relação a esses dados, em conformidade com a Lei Geral de Proteção de Dados (LGPD - Lei nº 13.709/2018).
          </p>
        ),
      },
      {
        title: "2. Quais Dados Coletamos?",
        content: (
          <>
            <p>Coletamos informações que você nos fornece diretamente, bem como dados gerados durante sua navegação em nosso site.</p>
            <h3>Informações Fornecidas por Você:</h3>
            <ul>
              <li><strong>Formulário de Contato/Agendamento:</strong> Nome, endereço de e-mail, número de telefone (opcional) e a mensagem com a descrição do seu problema ou solicitação.</li>
              <li><strong>Comunicação Direta (WhatsApp/Email):</strong> Seu número de telefone ou e-mail, nome e o conteúdo das nossas conversas.</li>
            </ul>
            <h3>Informações Coletadas Automaticamente:</h3>
            <ul>
              <li><strong>Dados de Navegação (Cookies):</strong> Informações anônimas como endereço IP, tipo de navegador, páginas visitadas e tempo de permanência, com o objetivo de melhorar nosso site.</li>
            </ul>
          </>
        ),
      },
      {
        title: "3. Como e Por Que Usamos Seus Dados?",
        content: (
          <>
            <p>Utilizamos seus dados pessoais para as seguintes finalidades:</p>
            <ul>
              <li><strong>Prestação de Serviços:</strong> Para responder às suas solicitações, agendar serviços, fornecer orçamentos e manter contato durante a execução do serviço.</li>
              <li><strong>Melhoria do Site:</strong> Para analisar o desempenho do nosso site, entender quais serviços são mais populares e melhorar a experiência do usuário.</li>
              <li><strong>Segurança:</strong> Para monitorar atividades, prevenir fraudes e proteger a segurança do nosso site e de nossos clientes.</li>
            </ul>
          </>
        ),
      },
      {
        title: "4. Seus Direitos (LGPD)",
        content: (
          <>
            <p>Você, como titular dos dados, possui direitos e pode exercê-los a qualquer momento. São eles:</p>
            <ul>
              <li><strong>Acesso aos dados:</strong> O direito de saber quais dos seus dados nós tratamos.</li>
              <li><strong>Correção:</strong> O direito de corrigir dados incompletos, inexatos ou desatualizados.</li>
              <li><strong>Eliminação:</strong> O direito de solicitar a exclusão de seus dados de nossas bases, exceto nos casos em que a lei exija a manutenção.</li>
              <li><strong>Portabilidade:</strong> O direito de solicitar a transferência de seus dados para outro fornecedor de serviço.</li>
              <li><strong>Informação:</strong> O direito de saber com quais entidades públicas ou privadas compartilhamos seus dados.</li>
              <li><strong>Revogação do consentimento:</strong> O direito de retirar seu consentimento para o uso de dados.</li>
            </ul>
          </>
        ),
      },
      {
        title: "5. Fale Conosco",
        content: (
          <p>Se tiver qualquer dúvida sobre esta política ou como tratamos seus dados, entre em contato: <a href="mailto:contato@cortexstudio.com.br">contato@cortexstudio.com.br</a>.</p>
        )
      }
    ],
  },
  // --- SEÇÃO DOS TERMOS DE USO ---
  termsOfUse: {
    title: "Termos de Uso",
    lastUpdated: "Última atualização: 3 de Outubro de 2025",
    anchorId: "termos-de-uso",
    sections: [
      {
        title: "1. Aceitação dos Termos",
        content: (
          <p>
            Bem-vindo à <strong>Cortex Studio</strong>. Ao acessar e utilizar nosso website e solicitar nossos serviços, você concorda em cumprir e estar vinculado aos seguintes termos e condições. Se você não concordar com estes termos, por favor, não utilize nosso site ou serviços.
          </p>
        ),
      },
      {
        title: "2. Descrição dos Serviços",
        content: (
          <p>
            A Cortex Studio oferece serviços especializados em manutenção, otimização e reparo de computadores. As descrições e os preços "a partir de" listados no site são informativos e podem variar dependendo do diagnóstico técnico final.
          </p>
        ),
      },
      {
        title: "3. Responsabilidades do Usuário",
        content: (
          <>
            <p>Ao solicitar um serviço, você concorda em:</p>
            <ul>
              <li>Fornecer informações precisas e verdadeiras sobre você e seu equipamento.</li>
              <li>Realizar o backup de todos os seus dados pessoais importantes antes de entregar o equipamento. A Cortex Studio não se responsabiliza por perda de dados não relacionada a uma falha comprovada durante o serviço.</li>
              <li>Aprovar formalmente o orçamento final antes do início de qualquer serviço.</li>
            </ul>
          </>
        ),
      },
      {
        title: "4. Garantia dos Serviços",
        content: (
          <p>
            Oferecemos uma garantia padrão de 90 (noventa) dias sobre a mão de obra e as peças utilizadas no serviço. Esta garantia não cobre problemas decorrentes de mau uso, danos acidentais ou software malicioso.
          </p>
        ),
      },
      {
        title: "5. Limitação de Responsabilidade",
        content: (
          <p>
            Nossa responsabilidade limita-se estritamente ao serviço contratado. Não nos responsabilizamos por problemas preexistentes ou falhas decorrentes do desgaste natural de componentes. Em serviços de recuperação de dados, não há garantia de que todos os dados possam ser recuperados.
          </p>
        ),
      },
      {
        title: "6. Contato",
        content: (
          <p>
            Para qualquer dúvida relacionada a estes termos, entre em contato conosco pelo e-mail: <a href="mailto:contato@cortexstudio.com.br">contato@cortexstudio.com.br</a>.
          </p>
        ),
      },
    ],
  },
};
